import play.api.mvc._
import slick.jdbc.PostgresProfile.api._

class ProductController(db: Database) extends Controller {

  def searchProducts = Action.async { request =>
    val queryParams = request.queryString

    val whereClauses = queryParams.flatMap {
      case ("name", values) => Some(values.map(name => sql"product_name LIKE '%' || $name || '%'"))
      case ("category", values) => Some(values.map(category => sql"category_id = ${category.head}"))
      case _ => None
    }

    val whereClause = whereClauses match {
      case Nil => sql"TRUE"
      case fragments => sql"AND (${fragments.mkString(" AND ")})"
    }

    val query = sql"SELECT * FROM products WHERE $whereClause".as[Product]

    db.run(query).map(products => Ok(Json.toJson(products)))
  }
